{
  "name": "DuoHome Finder",
  "description": "Uma aplicação colaborativa para casais encontrarem o imóvel ideal. Utilize o chat com IA (Gemini) para buscar opções reais na web e gerencie uma lista de favoritos compartilhada entre você e seu parceiro."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  HUSBAND = 'HUSBAND',
  WIFE = 'WIFE'
}

export interface User {
  id: UserRole;
  name: string;
  avatar: string;
  color: string;
}

export interface Property {
  id: string;
  title: string;
  location: string;
  price: string;
  description: string;
  features: string[];
  link?: string;
  addedBy: UserRole;
  addedAt: number;
  notes: Record<UserRole, string>; // Notes from both users
  imageUrl: string;
}

export interface GroundingSource {
  title: string;
  uri: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  userRole?: UserRole; // If user, which one?
  timestamp: number;
  sources?: GroundingSource[];
  isThinking?: boolean;
}

export interface SearchResult {
  web: {
    uri: string;
    title: string;
  }
}

import { GoogleGenAI, Type } from "@google/genai";
import { ChatMessage, SearchResult, GroundingSource } from "../types";

// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
Você é um consultor imobiliário especializado chamado "DuoHome AI".
Seu objetivo é ajudar um casal a encontrar o imóvel perfeito no Brasil.
Eles podem perguntar sobre bairros, preços, buscar listings reais ou pedir conselhos.

REGRAS:
1. Sempre use a ferramenta 'googleSearch' para encontrar listings reais e informações atualizadas sobre preços e imóveis disponíveis quando o usuário solicitar buscas específicas (ex: "apto em Pinheiros com 2 quartos").
2. Seja amigável, imparcial e conciso.
3. Formate preços em Reais (R$).
4. Se encontrar links de imóveis, mencione explicitamente no texto para que o usuário saiba.
5. Lembre-se que o casal está usando o app de forma colaborativa.
`;

export const sendMessageToGemini = async (
  history: ChatMessage[],
  newMessage: string
): Promise<{ text: string; sources: GroundingSource[] }> => {
  try {
    // Convert generic chat history to model history format if needed, 
    // but for simplicity in this stateless service, we'll just send the last few contexts + new message
    // or use a chat session. Here we will use generateContent with history as context string for simplicity in a single turn 
    // to ensure tools work reliably without managing complex chat session state objects across React renders.

    // Construct a "chat" style prompt manually to allow robust tool usage per request
    const context = history.slice(-5).map(h => `${h.role === 'user' ? 'User' : 'Model'}: ${h.text}`).join('\n');
    const prompt = `${context}\nUser: ${newMessage}\nModel:`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: newMessage, // We use the direct message and let the system instruction handle persona. 
      // Ideally pass full history but for search grounding, a direct query is often most effective.
      // Let's pass the instruction via config.
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }],
        thinkingConfig: { thinkingBudget: 0 } // Speed over deep reasoning for chat
      }
    });

    const text = response.text || "Desculpe, não consegui encontrar informações no momento.";

    // Extract Grounding Metadata
    const sources: GroundingSource[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          sources.push({
            title: chunk.web.title || "Fonte Web",
            uri: chunk.web.uri
          });
        }
      });
    }

    return { text, sources };

  } catch (error) {
    console.error("Gemini API Error:", error);
    return { 
      text: "Ocorreu um erro ao conectar com o serviço de busca. Por favor, tente novamente.", 
      sources: [] 
    };
  }
};

/**
 * Helper to suggest a structured property from a text description using Gemini
 * This allows the user to click "Magic Fill" when adding a property manually.
 */
export const parsePropertyDetails = async (description: string): Promise<any> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Extract real estate details from this text into JSON: "${description}".`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        location: { type: Type.STRING },
                        price: { type: Type.STRING },
                        features: { type: Type.ARRAY, items: { type: Type.STRING } }
                    }
                }
            }
        });
        return JSON.parse(response.text || "{}");
    } catch (e) {
        return {};
    }
}

