export default Layout;
export { USERS };

import React, { useState } from 'react';
import { MapPin, ExternalLink, Trash2, Edit3, Save } from 'lucide-react';
import { Property, UserRole } from '../types';
import { USERS } from './Layout';

interface PropertyCardProps {
  property: Property;
  currentUserRole: UserRole;
  onUpdateNote: (propertyId: string, role: UserRole, note: string) => void;
  onDelete: (propertyId: string) => void;
}

const PropertyCard: React.FC<PropertyCardProps> = ({ 
  property, 
  currentUserRole, 
  onUpdateNote,
  onDelete 
}) => {
  const [isEditingNote, setIsEditingNote] = useState(false);
  const [noteDraft, setNoteDraft] = useState(property.notes[currentUserRole] || '');

  const handleSaveNote = () => {
    onUpdateNote(property.id, currentUserRole, noteDraft);
    setIsEditingNote(false);
  };

  const creator = USERS[property.addedBy];

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden flex flex-col hover:shadow-md transition-shadow">
      <div className="relative h-48 bg-gray-200">
        <img 
          src={property.imageUrl} 
          alt={property.title}
          className="w-full h-full object-cover"
        />
        <div className="absolute top-2 right-2">
            <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-white/90 shadow-sm backdrop-blur-sm ${property.addedBy === UserRole.HUSBAND ? 'text-indigo-700' : 'text-rose-700'}`}>
                Adicionado por {creator.avatar}
            </span>
        </div>
      </div>

      <div className="p-4 flex-1 flex flex-col">
        <div className="flex justify-between items-start mb-2">
            <div>
                <h3 className="text-lg font-bold text-gray-900 line-clamp-1">{property.title}</h3>
                <p className="text-sm text-gray-500 flex items-center gap-1 mt-1">
                    <MapPin className="w-3.5 h-3.5" />
                    {property.location}
                </p>
            </div>
            <p className="text-lg font-semibold text-emerald-600 whitespace-nowrap">
                {property.price}
            </p>
        </div>

        <p className="text-sm text-gray-600 line-clamp-2 mb-3">
            {property.description}
        </p>

        {property.features.length > 0 && (
            <div className="flex flex-wrap gap-1 mb-4">
                {property.features.slice(0, 3).map((f, i) => (
                    <span key={i} className="px-2 py-1 bg-gray-100 text-gray-600 text-xs rounded-md">
                        {f}
                    </span>
                ))}
            </div>
        )}

        <div className="mt-auto pt-4 border-t border-gray-100">
            {/* Notes Section */}
            <div className="space-y-3">
                {/* Partner's Note (Read Only) */}
                {Object.values(UserRole).map((role) => {
                    if (role === currentUserRole) return null;
                    const note = property.notes[role];
                    const user = USERS[role];
                    if (!note) return null;
                    return (
                        <div key={role} className="flex gap-2 text-sm bg-gray-50 p-2 rounded-lg">
                            <span className="shrink-0 text-lg">{user.avatar}</span>
                            <p className="text-gray-600 italic">"{note}"</p>
                        </div>
                    );
                })}

                {/* My Note (Editable) */}
                <div className="flex flex-col gap-1">
                    <div className="flex items-center justify-between">
                         <span className="text-xs font-medium text-gray-500 flex items-center gap-1">
                             {USERS[currentUserRole].avatar} Minha observação
                         </span>
                         {!isEditingNote && (
                             <button 
                                onClick={() => setIsEditingNote(true)}
                                className="text-xs text-indigo-600 hover:underline"
                             >
                                 Editar
                             </button>
                         )}
                    </div>

                    {isEditingNote ? (
                        <div className="flex gap-2 mt-1">
                            <input 
                                type="text" 
                                value={noteDraft}
                                onChange={(e) => setNoteDraft(e.target.value)}
                                className="flex-1 text-sm border border-gray-300 rounded px-2 py-1 focus:outline-none focus:border-indigo-500"
                                placeholder="O que você achou?"
                            />
                            <button 
                                onClick={handleSaveNote}
                                className="bg-indigo-600 text-white p-1 rounded hover:bg-indigo-700"
                            >
                                <Save className="w-4 h-4" />
                            </button>
                        </div>
                    ) : (
                        <p className={`text-sm ${property.notes[currentUserRole] ? 'text-gray-800' : 'text-gray-400 italic'}`}>
                            {property.notes[currentUserRole] || "Toque em editar para adicionar uma nota..."}
                        </p>
                    )}
                </div>
            </div>
        </div>

        <div className="flex justify-between items-center mt-4 pt-2">
            {property.link && (
                <a 
                    href={property.link} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="flex items-center gap-1 text-sm font-medium text-indigo-600 hover:text-indigo-800"
                >
                    Ver original <ExternalLink className="w-3 h-3" />
                </a>
            )}
            <button 
                onClick={() => onDelete(property.id)}
                className="text-gray-400 hover:text-red-500 transition-colors p-1"
                title="Remover dos favoritos"
            >
                <Trash2 className="w-4 h-4" />
            </button>
        </div>
      </div>
    </div>
  );
};

export default PropertyCard;

import React, { useState } from 'react';
import { X, Sparkles, Loader2 } from 'lucide-react';
import { UserRole } from '../types';
import { parsePropertyDetails } from '../services/geminiService';

interface AddPropertyModalProps {
  isOpen: boolean;
  onClose: () => void;
  onAdd: (data: any) => void;
  currentUserRole: UserRole;
}

const AddPropertyModal: React.FC<AddPropertyModalProps> = ({ isOpen, onClose, onAdd, currentUserRole }) => {
  const [loading, setLoading] = useState(false);
  const [description, setDescription] = useState('');

  // Form States
  const [title, setTitle] = useState('');
  const [price, setPrice] = useState('');
  const [location, setLocation] = useState('');
  const [link, setLink] = useState('');
  const [note, setNote] = useState('');

  const handleMagicFill = async () => {
    if (!description) return;
    setLoading(true);
    try {
        const details = await parsePropertyDetails(description);
        if (details.title) setTitle(details.title);
        if (details.price) setPrice(details.price);
        if (details.location) setLocation(details.location);
    } catch (e) {
        console.error("Failed to parse", e);
    } finally {
        setLoading(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAdd({
        title: title || "Imóvel sem título",
        price: price || "Preço sob consulta",
        location: location || "Localização não informada",
        description: description,
        link: link,
        note: note
    });
    // Reset
    setTitle('');
    setPrice('');
    setLocation('');
    setDescription('');
    setLink('');
    setNote('');
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl w-full max-w-md max-h-[90vh] overflow-y-auto shadow-2xl animate-in fade-in zoom-in duration-200">
        <div className="sticky top-0 bg-white border-b border-gray-100 p-4 flex justify-between items-center">
            <h2 className="text-lg font-bold text-gray-800">Adicionar Imóvel</h2>
            <button onClick={onClose} className="p-1 hover:bg-gray-100 rounded-full">
                <X className="w-5 h-5 text-gray-500" />
            </button>
        </div>

        <div className="p-6 space-y-4">
            {/* AI Helper */}
            <div className="bg-indigo-50 p-3 rounded-lg border border-indigo-100">
                <label className="block text-xs font-semibold text-indigo-800 mb-1">
                    Preenchimento Rápido com IA
                </label>
                <div className="flex gap-2">
                    <input 
                        type="text" 
                        value={description}
                        onChange={(e) => setDescription(e.target.value)}
                        placeholder="Cole aqui a descrição do anúncio..."
                        className="flex-1 text-sm border border-indigo-200 rounded px-3 py-2 focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                    />
                    <button 
                        onClick={handleMagicFill}
                        disabled={loading || !description}
                        className="bg-indigo-600 text-white px-3 rounded hover:bg-indigo-700 disabled:opacity-50 flex items-center justify-center"
                    >
                        {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
                    </button>
                </div>
            </div>

            <form id="add-property-form" onSubmit={handleSubmit} className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Título / Nome</label>
                    <input required value={title} onChange={e => setTitle(e.target.value)} className="w-full border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="Ex: Apto 2 quartos em Pinheiros" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Preço</label>
                        <input value={price} onChange={e => setPrice(e.target.value)} className="w-full border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="R$ 3.500" />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Localização</label>
                        <input value={location} onChange={e => setLocation(e.target.value)} className="w-full border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="Bairro, Cidade" />
                    </div>
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Link do Anúncio (Opcional)</label>
                    <input type="url" value={link} onChange={e => setLink(e.target.value)} className="w-full border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="https://..." />
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Sua observação inicial</label>
                    <textarea value={note} onChange={e => setNote(e.target.value)} rows={2} className="w-full border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="O que te chamou atenção?" />
                </div>
            </form>
        </div>

        <div className="sticky bottom-0 bg-gray-50 p-4 border-t border-gray-200">
            <button 
                type="submit" 
                form="add-property-form"
                className="w-full bg-gray-900 text-white py-3 rounded-xl font-semibold hover:bg-black transition-colors"
            >
                Adicionar aos Favoritos
            </button>
        </div>
      </div>
    </div>
  );
};

export default AddPropertyModal;

import React, { useState, useEffect, useRef } from 'react';
import { Send, Plus, Search, MapPin, ExternalLink, Bot } from 'lucide-react';
import Layout, { USERS } from './components/Layout';
import PropertyCard from './components/PropertyCard';
import AddPropertyModal from './components/AddPropertyModal';
import { UserRole, Property, ChatMessage } from './types';
import { sendMessageToGemini } from './services/geminiService';

const MOCK_INITIAL_FAVORITES: Property[] = [
  {
    id: '1',
    title: 'Apartamento Jardins Moderno',
    location: 'Jardim Paulista, SP',
    price: 'R$ 4.500/mês',
    description: 'Apartamento renovado com vista para o parque, 2 quartos, 1 vaga.',
    features: ['2 Quartos', 'Portaria 24h', 'Academia'],
    addedBy: UserRole.HUSBAND,
    addedAt: Date.now(),
    notes: {
      [UserRole.HUSBAND]: 'Achei o preço bom pela localização.',
      [UserRole.WIFE]: 'Gostei, mas achei a cozinha pequena.'
    },
    imageUrl: 'https://picsum.photos/400/300?random=1'
  },
  {
    id: '2',
    title: 'Casa de Vila Charmosa',
    location: 'Vila Madalena, SP',
    price: 'R$ 6.200/mês',
    description: 'Casa em vila fechada, muito segura, quintal arborizado.',
    features: ['3 Quartos', 'Quintal', 'Segurança'],
    addedBy: UserRole.WIFE,
    addedAt: Date.now(),
    notes: {
      [UserRole.HUSBAND]: '',
      [UserRole.WIFE]: 'Perfeita para o cachorro!'
    },
    imageUrl: 'https://picsum.photos/400/300?random=2'
  }
];

export default function App() {
  const [currentUserRole, setCurrentUserRole] = useState<UserRole>(UserRole.HUSBAND);
  const [activeTab, setActiveTab] = useState<'chat' | 'favorites'>('chat');
  const [favorites, setFavorites] = useState<Property[]>(MOCK_INITIAL_FAVORITES);
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: '0',
      role: 'model',
      text: 'Olá! Sou a DuoHome AI. Como posso ajudar vocês a encontrarem o novo lar hoje? Me digam o bairro, faixa de preço ou características que procuram.',
      timestamp: Date.now()
    }
  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const currentUser = USERS[currentUserRole];

  // Scroll to bottom of chat
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, activeTab]);

  const handleSendMessage = async () => {
    if (!inputMessage.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: inputMessage,
      userRole: currentUserRole,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputMessage('');
    setIsTyping(true);

    try {
      const response = await sendMessageToGemini(messages, userMsg.text);

      const botMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response.text,
        timestamp: Date.now(),
        sources: response.sources
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error("Error sending message", error);
    } finally {
      setIsTyping(false);
    }
  };

  const handleAddProperty = (data: any) => {
    const newProperty: Property = {
        id: Date.now().toString(),
        title: data.title,
        price: data.price,
        location: data.location,
        description: data.description,
        features: [],
        link: data.link,
        addedBy: currentUserRole,
        addedAt: Date.now(),
        imageUrl: `https://picsum.photos/400/300?random=${Date.now()}`,
        notes: {
            [UserRole.HUSBAND]: currentUserRole === UserRole.HUSBAND ? data.note : '',
            [UserRole.WIFE]: currentUserRole === UserRole.WIFE ? data.note : ''
        }
    };
    setFavorites(prev => [newProperty, ...prev]);
    setActiveTab('favorites');
  };

  const handleUpdateNote = (propertyId: string, role: UserRole, note: string) => {
    setFavorites(prev => prev.map(p => {
        if (p.id !== propertyId) return p;
        return {
            ...p,
            notes: {
                ...p.notes,
                [role]: note
            }
        };
    }));
  };

  const handleDeleteProperty = (id: string) => {
      if (window.confirm("Tem certeza que deseja remover este imóvel da lista?")) {
        setFavorites(prev => prev.filter(p => p.id !== id));
      }
  };

  return (
    <Layout 
      currentUser={currentUser} 
      onSwitchUser={setCurrentUserRole}
