import { GoogleGenAI, Type } from "@google/genai";
import { ChatMessage, SearchResult, GroundingSource, SearchFilters } from "../types";

// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const BASE_SYSTEM_INSTRUCTION = `
Você é um consultor imobiliário especializado chamado "DuoHome AI".
Seu objetivo é ajudar um casal a encontrar o imóvel perfeito no Brasil.

REGRAS GERAIS:
1. Sempre use a ferramenta 'googleSearch' para encontrar listings reais e informações atualizadas.
2. Seja amigável, imparcial e conciso.
3. Formate preços em Reais (R$).
4. Se encontrar links de imóveis, mencione explicitamente no texto.
`;

export const sendMessageToGemini = async (
  history: ChatMessage[],
  newMessage: string,
  filters?: SearchFilters
): Promise<{ text: string; sources: GroundingSource[] }> => {
  try {
    // Construct system instruction with active filters
    let systemInstruction = BASE_SYSTEM_INSTRUCTION;
    if (filters) {
      const criteria = [];
      if (filters.bedrooms > 0) criteria.push(`Mínimo de ${filters.bedrooms} quartos`);
      if (filters.bathrooms > 0) criteria.push(`Mínimo de ${filters.bathrooms} banheiros`);
      if (filters.maxPrice > 0) criteria.push(`Preço máximo de R$ ${filters.maxPrice}`);
      if (filters.petFriendly) criteria.push(`Aceita animais de estimação (Pet Friendly)`);

      if (criteria.length > 0) {
        systemInstruction += `\n\nCRITÉRIOS DE BUSCA ATIVOS (Priorize estes filtros): \n- ${criteria.join('\n- ')}`;
      }
    }

    // Construct context
    const context = history.slice(-5).map(h => `${h.role === 'user' ? 'User' : 'Model'}: ${h.text}`).join('\n');
    const prompt = `${context}\nUser: ${newMessage}\nModel:`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: newMessage,
      config: {
        systemInstruction: systemInstruction,
        tools: [{ googleSearch: {} }],
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    const text = response.text || "Desculpe, não consegui encontrar informações no momento.";

    // Extract Grounding Metadata
    const sources: GroundingSource[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          sources.push({
            title: chunk.web.title || "Fonte Web",
            uri: chunk.web.uri
          });
        }
      });
    }

    return { text, sources };

  } catch (error) {
    console.error("Gemini API Error:", error);
    return { 
      text: "Ocorreu um erro ao conectar com o serviço de busca. Por favor, tente novamente.", 
      sources: [] 
    };
  }
};

export const parsePropertyDetails = async (description: string): Promise<any> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Extract real estate details from this text into JSON: "${description}".`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        location: { type: Type.STRING },
                        price: { type: Type.STRING },
                        features: { type: Type.ARRAY, items: { type: Type.STRING } }
                    }
                }
            }
        });
        return JSON.parse(response.text || "{}");
    } catch (e) {
        return {};
    }
}

