  const [price, setPrice] = useState('');
  const [location, setLocation] = useState('');
  const [link, setLink] = useState('');
  const [comment, setComment] = useState('');
  const [rating, setRating] = useState(0);
  const [isPrivate, setIsPrivate] = useState(false);

  const handleMagicFill = async () => {
    if (!description) return;
    setLoading(true);
    try {
        const details = await parsePropertyDetails(description);
        if (details.title) setTitle(details.title);
        if (details.price) setPrice(details.price);
        if (details.location) setLocation(details.location);
    } catch (e) {
        console.error("Failed to parse", e);
    } finally {
        setLoading(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAdd({
        title: title || "Imóvel sem título",
        price: price || "Preço sob consulta",
        location: location || "Localização não informada",
        description: description,
        link: link,
        comment: comment,
        rating: rating,
        isPrivate: isPrivate
    });
    // Reset
    setTitle('');
    setPrice('');
    setLocation('');
    setDescription('');
    setLink('');
    setComment('');
    setRating(0);
    setIsPrivate(false);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl w-full max-w-md max-h-[90vh] overflow-y-auto shadow-2xl animate-in fade-in zoom-in duration-200">
        <div className="sticky top-0 bg-white border-b border-gray-100 p-4 flex justify-between items-center z-10">
            <h2 className="text-lg font-bold text-gray-800">Adicionar Imóvel</h2>
            <button onClick={onClose} className="p-1 hover:bg-gray-100 rounded-full">
                <X className="w-5 h-5 text-gray-500" />
            </button>
        </div>

        <div className="p-6 space-y-4">
            {/* AI Helper */}
            <div className="bg-indigo-50 p-3 rounded-lg border border-indigo-100">
                <label className="block text-xs font-semibold text-indigo-800 mb-1">
                    Preenchimento Rápido com IA
                </label>
                <div className="flex gap-2">
                    <input 
                        type="text" 
                        value={description}
                        onChange={(e) => setDescription(e.target.value)}
                        placeholder="Cole aqui a descrição do anúncio..."
                        className="flex-1 text-sm border border-indigo-200 rounded px-3 py-2 focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                    />
                    <button 
                        onClick={handleMagicFill}
                        disabled={loading || !description}
                        className="bg-indigo-600 text-white px-3 rounded hover:bg-indigo-700 disabled:opacity-50 flex items-center justify-center"
                    >
                        {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
                    </button>
                </div>
            </div>

            <form id="add-property-form" onSubmit={handleSubmit} className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Título / Nome</label>
                    <input required value={title} onChange={e => setTitle(e.target.value)} className="w-full border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="Ex: Apto 2 quartos em Pinheiros" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Preço</label>
                        <input value={price} onChange={e => setPrice(e.target.value)} className="w-full border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="R$ 3.500" />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Localização</label>
                        <input value={location} onChange={e => setLocation(e.target.value)} className="w-full border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="Bairro, Cidade" />
                    </div>
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Link do Anúncio (Opcional)</label>
                    <input type="url" value={link} onChange={e => setLink(e.target.value)} className="w-full border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="https://..." />
                </div>

                {/* Privacy Toggle */}
                <div 
                    onClick={() => setIsPrivate(!isPrivate)}
                    className={`flex items-center justify-between p-3 rounded-lg border cursor-pointer transition-all ${isPrivate ? 'bg-gray-800 border-gray-800 text-white' : 'bg-gray-50 border-gray-200 text-gray-600'}`}
                >
                    <div className="flex items-center gap-2">
                        {isPrivate ? <Lock className="w-4 h-4" /> : <Globe className="w-4 h-4" />}
                        <span className="text-sm font-medium">{isPrivate ? 'Salvar na Minha Lista Privada' : 'Salvar na Lista Compartilhada'}</span>
                    </div>
                    <div className={`w-10 h-5 rounded-full relative transition-colors ${isPrivate ? 'bg-gray-600' : 'bg-gray-300'}`}>
                        <div className={`w-3 h-3 bg-white rounded-full absolute top-1 transition-transform ${isPrivate ? 'left-6' : 'left-1'}`} />
                    </div>
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Sua avaliação inicial</label>
                    <textarea value={comment} onChange={e => setComment(e.target.value)} rows={2} className="w-full border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="O que te chamou atenção?" />
                </div>
            </form>
        </div>

        <div className="sticky bottom-0 bg-gray-50 p-4 border-t border-gray-200">
            <button 
                type="submit" 
                form="add-property-form"
                className="w-full bg-gray-900 text-white py-3 rounded-xl font-semibold hover:bg-black transition-colors"
            >
                Salvar Imóvel
            </button>
        </div>
      </div>
    </div>
  );
};

export default AddPropertyModal;

import React, { useState, useEffect, useRef } from 'react';
import { Send, Plus, Search, MapPin, ExternalLink, Bot, SlidersHorizontal, User as UserIcon } from 'lucide-react';
import Layout, { USERS } from './components/Layout';
import PropertyCard from './components/PropertyCard';
import AddPropertyModal from './components/AddPropertyModal';
import SearchFiltersModal from './components/SearchFilters';
import { UserRole, Property, ChatMessage, Review, SearchFilters, User } from './types';
import { sendMessageToGemini } from './services/geminiService';

// Updated mock data with reviews structure and isPrivate
const MOCK_INITIAL_FAVORITES: Property[] = [
  {
    id: '1',
    title: 'Apartamento Jardins Moderno',
    location: 'Jardim Paulista, SP',
    price: 'R$ 4.500/mês',
    description: 'Apartamento renovado com vista para o parque, 2 quartos, 1 vaga.',
    features: ['2 Quartos', 'Portaria 24h', 'Academia'],
    addedBy: UserRole.HUSBAND,
    addedAt: Date.now(),
    isPrivate: false,
    reviews: [
      { userId: UserRole.HUSBAND, rating: 4, comment: 'Achei o preço bom pela localização.', timestamp: Date.now() },
      { userId: UserRole.WIFE, rating: 3, comment: 'Gostei, mas achei a cozinha pequena.', timestamp: Date.now() }
    ],
    imageUrl: 'https://picsum.photos/400/300?random=1'
  },
  {
    id: '2',
    title: 'Casa de Vila Charmosa',
    location: 'Vila Madalena, SP',
    price: 'R$ 6.200/mês',
    description: 'Casa em vila fechada, muito segura, quintal arborizado.',
    features: ['3 Quartos', 'Quintal', 'Segurança'],
    addedBy: UserRole.WIFE,
    addedAt: Date.now(),
    isPrivate: false,
    reviews: [
      { userId: UserRole.WIFE, rating: 5, comment: 'Perfeita para o cachorro!', timestamp: Date.now() }
    ],
    imageUrl: 'https://picsum.photos/400/300?random=2'
  }
];

const DEFAULT_FILTERS: SearchFilters = {
  bedrooms: 0,
  bathrooms: 0,
  maxPrice: 0,
  petFriendly: false
};

export default function App() {
  const [currentUserRole, setCurrentUserRole] = useState<UserRole>(UserRole.HUSBAND);
  const [activeTab, setActiveTab] = useState<'chat' | 'favorites'>('chat');
  const [favorites, setFavorites] = useState<Property[]>(MOCK_INITIAL_FAVORITES);
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: '0',
      role: 'model',
      text: 'Olá! Sou a DuoHome AI. Configure seus filtros de busca ou me diga o que procura para começarmos!',
      timestamp: Date.now()
    }
  ]);

  // User Preferences State (Mock persistence in memory)
  const [userPreferences, setUserPreferences] = useState<Record<UserRole, SearchFilters>>({
    [UserRole.HUSBAND]: { ...DEFAULT_FILTERS },
    [UserRole.WIFE]: { ...DEFAULT_FILTERS }
  });

  const [inputMessage, setInputMessage] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isFiltersOpen, setIsFiltersOpen] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const currentUser = { ...USERS[currentUserRole], preferences: userPreferences[currentUserRole] };

  // Scroll to bottom of chat
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, activeTab]);

  const handleUpdateFilters = (newFilters: SearchFilters) => {
    setUserPreferences(prev => ({
      ...prev,
      [currentUserRole]: newFilters
    }));
  };

  const handleSendMessage = async () => {
    if (!inputMessage.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: inputMessage,
      userRole: currentUserRole,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputMessage('');
    setIsTyping(true);

    try {
      // Pass the current user's preferences as filters context
      const response = await sendMessageToGemini(messages, userMsg.text, currentUser.preferences);

      const botMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response.text,
        timestamp: Date.now(),
        sources: response.sources
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error("Error sending message", error);
    } finally {
      setIsTyping(false);
    }
  };

  const handleAddProperty = (data: any) => {
    const newProperty: Property = {
        id: Date.now().toString(),
        title: data.title,
        price: data.price,
        location: data.location,
        description: data.description,
        features: [],
        link: data.link,
        addedBy: currentUserRole,
        addedAt: Date.now(),
        isPrivate: data.isPrivate,
        imageUrl: `https://picsum.photos/400/300?random=${Date.now()}`,
        reviews: data.comment ? [{
            userId: currentUserRole,
            rating: data.rating || 0,
            comment: data.comment,
            timestamp: Date.now()
        }] : []
    };
    setFavorites(prev => [newProperty, ...prev]);
    setActiveTab('favorites');
  };

  const handleUpdateReview = (propertyId: string, review: Review) => {
    setFavorites(prev => prev.map(p => {
        if (p.id !== propertyId) return p;
        const otherReviews = p.reviews.filter(r => r.userId !== review.userId);
        return {
            ...p,
            reviews: [...otherReviews, review]
        };
    }));
  };

  const handleTogglePrivacy = (propertyId: string) => {
      setFavorites(prev => prev.map(p => {
          if (p.id !== propertyId) return p;
          // Only owner can toggle
          if (p.addedBy !== currentUserRole) return p;
          return { ...p, isPrivate: !p.isPrivate };
      }));
  }

  const handleDeleteProperty = (id: string) => {
      if (window.confirm("Tem certeza que deseja remover este imóvel da lista?")) {
        setFavorites(prev => prev.filter(p => p.id !== id));
      }
  };

  // Filter properties based on privacy rules
  const visibleFavorites = favorites.filter(p => {
      // If public, everyone sees it
      if (!p.isPrivate) return true;
      // If private, only the owner sees it
      return p.addedBy === currentUserRole;
  });

  const activeFiltersCount = Object.values(currentUser.preferences).filter(v => v !== 0 && v !== false).length;

  return (
    <Layout 
      currentUser={currentUser} 
      onSwitchUser={setCurrentUserRole}
      activeTab={activeTab}
      onTabChange={setActiveTab}
    >
      {activeTab === 'chat' ? (
        <div className="flex flex-col h-full">
          {/* Filters Bar */}
          <div className="bg-white px-4 py-2 border-b border-gray-100 flex items-center gap-2 overflow-x-auto whitespace-nowrap scrollbar-hide">
            <button 
              onClick={() => setIsFiltersOpen(true)}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-bold transition-all ${activeFiltersCount > 0 ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-600'}`}
            >
              <SlidersHorizontal className="w-3 h-3" />
              Filtros {activeFiltersCount > 0 && `(${activeFiltersCount})`}
            </button>

            {/* Display active filter chips */}
            {currentUser.preferences.bedrooms > 0 && <span className="text-xs bg-indigo-50 text-indigo-700 px-2 py-1 rounded-md border border-indigo-100">{currentUser.preferences.bedrooms}+ Quartos</span>}
            {currentUser.preferences.maxPrice > 0 && <span className="text-xs bg-indigo-50 text-indigo-700 px-2 py-1 rounded-md border border-indigo-100">Max R$ {currentUser.preferences.maxPrice}</span>}
            {currentUser.preferences.petFriendly && <span className="text-xs bg-indigo-50 text-indigo-700 px-2 py-1 rounded-md border border-indigo-100">Pet Friendly</span>}
          </div>

          {/* Chat Area */}
          <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {messages.map((msg) => (
              <div 
                key={msg.id} 
                className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                <div className={`max-w-[85%] flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                    {msg.role === 'user' && msg.userRole && (
                        <span className="text-[10px] text-gray-500 mb-1 mr-1">
                            {USERS[msg.userRole].name}
                        </span>
                    )}

                    <div className={`
                        p-3 rounded-2xl shadow-sm text-sm sm:text-base whitespace-pre-wrap
                        ${msg.role === 'user' 
                          ? `${USERS[msg.userRole!].color} text-white rounded-br-none` 
                          : 'bg-white border border-gray-200 text-gray-800 rounded-bl-none'}
                    `}>
                        {msg.role === 'model' && (
                            <div className="flex items-center gap-1 mb-1 text-indigo-600 font-semibold text-xs uppercase tracking-wider">
                                <Bot className="w-3 h-3" /> Assistant
                            </div>
                        )}
                        {msg.text}
                    </div>

                    {msg.sources && msg.sources.length > 0 && (
                        <div className="mt-2 bg-indigo-50 border border-indigo-100 rounded-lg p-2 w-full">
                            <p className="text-xs font-semibold text-indigo-800 mb-1 flex items-center gap-1">
                                <Search className="w-3 h-3" /> Fontes encontradas:
                            </p>
                            <div className="flex flex-col gap-1">
                                {msg.sources.map((source, idx) => (
                                    <a 
                                        key={idx} 
                                        href={source.uri} 
                                        target="_blank" 
                                        rel="noopener noreferrer"
                                        className="text-xs text-indigo-600 truncate hover:underline flex items-center gap-1"
                                    >
                                        <ExternalLink className="w-3 h-3" />
                                        {source.title}
                                    </a>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
              </div>
            ))}
            {isTyping && (
                <div className="flex justify-start w-full">
                    <div className="bg-white border border-gray-200 p-3 rounded-2xl rounded-bl-none shadow-sm flex items-center gap-2">
                         <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></div>
                         <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-75"></div>
                         <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-150"></div>
                    </div>
                </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          <div className="absolute bottom-20 right-4 z-10">
              <button 
                onClick={() => setIsAddModalOpen(true)}
                className="bg-gray-900 text-white p-3 rounded-full shadow-lg hover:bg-black transition-transform active:scale-95 flex items-center gap-2"
              >
                  <Plus className="w-5 h-5" />
                  <span className="text-sm font-medium pr-1">Salvar Imóvel</span>
              </button>
          </div>

          <div className="bg-white p-4 border-t border-gray-200">
            <div className="relative flex items-center gap-2">
              <input
                type="text"
                value={inputMessage}
                onChange={(e) => setInputMessage(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                placeholder={`Como ${currentUser.name.split(' ')[0]}, pergunte algo...`}
                className="flex-1 bg-gray-100 text-gray-900 placeholder-gray-500 border-0 rounded-full py-3 px-4 focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all"
              />
              <button
                onClick={handleSendMessage}
                disabled={!inputMessage.trim() || isTyping}
                className={`p-3 rounded-full flex-shrink-0 transition-colors ${
                  !inputMessage.trim() 
                    ? 'bg-gray-200 text-gray-400 cursor-not-allowed' 
                    : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-md'
                }`}
              >
                <Send className="w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      ) : (
        <div className="flex-1 overflow-y-auto p-4">
            <div className="flex justify-between items-center mb-6">
                <div>
                    <h2 className="text-2xl font-bold text-gray-800">Seus Favoritos</h2>
                    <p className="text-sm text-gray-500">
                        {visibleFavorites.filter(f => f.isPrivate).length > 0 
                            ? "Exibindo lista pessoal e compartilhada" 
                            : "Mostrando todos os imóveis compartilhados"}
                    </p>
                </div>
                <button 
                    onClick={() => setIsAddModalOpen(true)}
                    className="bg-indigo-600 text-white p-2 rounded-full hover:bg-indigo-700 shadow-sm"
                >
                    <Plus className="w-5 h-5" />
                </button>
            </div>

            {visibleFavorites.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-64 text-gray-400">
                    <MapPin className="w-12 h-12 mb-2 opacity-20" />
                    <p>Nenhum imóvel salvo.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {visibleFavorites.map((prop) => (
                        <PropertyCard 
                            key={prop.id} 
                            property={prop} 
                            currentUserRole={currentUserRole}
                            onUpdateReview={handleUpdateReview}
                            onTogglePrivacy={handleTogglePrivacy}
                            onDelete={handleDeleteProperty}
                        />
                    ))}
                </div>
            )}
        </div>
      )}

      <AddPropertyModal 
        isOpen={isAddModalOpen} 
        onClose={() => setIsAddModalOpen(false)} 
        onAdd={handleAddProperty}
        currentUserRole={currentUserRole}
      />

      <SearchFiltersModal
        isOpen={isFiltersOpen}
        onClose={() => setIsFiltersOpen(false)}
        filters={currentUser.preferences}
        onChange={handleUpdateFilters}
      />
    </Layout>
  );
}

import React from 'react';
import { Home, MessageCircle, Heart, User as UserIcon } from 'lucide-react';
import { User, UserRole } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  currentUser: User;
  onSwitchUser: (role: UserRole) => void;
  activeTab: 'chat' | 'favorites';
  onTabChange: (tab: 'chat' | 'favorites') => void;
}

const USERS: Record<UserRole, Omit<User, 'preferences'>> = {
  [UserRole.HUSBAND]: {
    id: UserRole.HUSBAND,
    name: 'Eu (Marido)',
    avatar: '👨🏻',
    color: 'bg-indigo-600'
  },
  [UserRole.WIFE]: {
    id: UserRole.WIFE,
    name: 'Ela (Esposa)',
    avatar: '👩🏼',
    color: 'bg-rose-500'
  }
};

const Layout: React.FC<LayoutProps> = ({ 
  children, 
  currentUser, 
  onSwitchUser,
  activeTab,
  onTabChange
}) => {
  return (
    <div className="flex flex-col h-screen bg-gray-50 overflow-hidden">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 px-4 py-3 flex items-center justify-between shrink-0 z-10">
        <div className="flex items-center gap-2">
          <div className="bg-gradient-to-tr from-indigo-500 to-rose-500 p-2 rounded-lg">
            <Home className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-xl font-bold text-gray-800 tracking-tight hidden sm:block">DuoHome</h1>
        </div>

        {/* User Switcher */}
        <div className="flex bg-gray-100 p-1 rounded-full items-center">
          {(Object.keys(USERS) as UserRole[]).map((role) => (
            <button
              key={role}
              onClick={() => onSwitchUser(role)}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-medium transition-all ${
                currentUser.id === role 
                  ? 'bg-white text-gray-800 shadow-sm' 
                  : 'text-gray-500 hover:text-gray-700'
              }`}
            >
              <span>{USERS[role].avatar}</span>
              <span className="hidden sm:inline">{role === UserRole.HUSBAND ? 'Eu' : 'Ela'}</span>
            </button>
          ))}
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-hidden relative flex flex-col">
        {children}
      </main>

      {/* Bottom Navigation */}
      <nav className="bg-white border-t border-gray-200 shrink-0">
        <div className="flex justify-around items-center">
          <button
            onClick={() => onTabChange('chat')}
            className={`flex flex-col items-center justify-center w-full py-3 gap-1 ${
              activeTab === 'chat' ? 'text-indigo-600' : 'text-gray-400 hover:text-gray-600'
            }`}
          >
            <MessageCircle className="w-6 h-6" />
            <span className="text-xs font-medium">Chat Assistant</span>
          </button>

          <div className="w-px h-8 bg-gray-200"></div>

          <button
            onClick={() => onTabChange('favorites')}
            className={`flex flex-col items-center justify-center w-full py-3 gap-1 ${
              activeTab === 'favorites' ? 'text-rose-500' : 'text-gray-400 hover:text-gray-600'
            }`}
          >
            <Heart className="w-6 h-6" />
            <span className="text-xs font-medium">Favoritos</span>
          </button>
        </div>
      </nav>
    </div>
  );
};

export default Layout;
export { USERS };
